int** createMatrix(const std::vector<std::vector<int>>& vec_matrix, int dimension) {
    int** matrix = new int*[dimension];
    for (int i = 0; i < dimension; ++i) {
        matrix[i] = new int[dimension];
        for (int j = 0; j < dimension; ++j) {
            matrix[i][j] = vec_matrix[i][j];
        }
    }
    return matrix;
}

void deleteMatrix(int** matrix, int dimension) {
    for (int i = 0; i < dimension; ++i) {
        delete[] matrix[i];
    }
    delete[] matrix;
}

void run_test(const std::string& input_str, const std::string& expected_str) {
    std::vector<std::vector<int>> vec_matrix;
    int dimension;
    // Simple parsing (assuming format [[...],[...]], dim)
    size_t comma_pos = input_str.find("],");
    std::string matrix_str = input_str.substr(0, comma_pos + 1);
    dimension = std::stoi(input_str.substr(comma_pos + 3));

    // Parse matrix_str into vec_matrix
    size_t start = matrix_str.find("[", 1);
    while (start != std::string::npos) {
        size_t end = matrix_str.find("]", start);
        std::string row_str = matrix_str.substr(start + 1, end - start - 1);
        std::vector<int> row;
        size_t val_start = 0;
        while(val_start < row_str.length()) {
            size_t val_end = row_str.find(",", val_start);
            row.push_back(std::stoi(row_str.substr(val_start, val_end - val_start)));
            if (val_end == std::string::npos) break;
            val_start = val_end + 1;
        }
        vec_matrix.push_back(row);
        start = matrix_str.find("[", end);
    }

    int** matrix = createMatrix(vec_matrix, dimension);
    bool actual_result = isSymmetric(matrix, dimension);
    deleteMatrix(matrix, dimension);
    bool expected_result = (expected_str == "true");

    if (actual_result == expected_result) {
        std::cout << "Test Passed" << std::endl;
    } else {
        std::cout << "Test Failed: Expected " << expected_str << ", Got " << (actual_result ? "true" : "false") << std::endl;
    }
}

int main() {
    run_test("[[1,2,3],[2,4,5],[3,5,6]], 3", "true");
    run_test("[[1,2,3],[4,5,6],[7,8,9]], 3", "false");
    run_test("[[10]], 1", "true");
    return 0;
}
